const sw=document.getElementById('sw'),code=document.getElementById('code');
const r=()=>Math.floor(Math.random()*360);
function gen(){const a=r(),b=(a+90+Math.floor(Math.random()*120))%360;const g=`linear-gradient(135deg,hsl(${a} 90% 60%),hsl(${b} 90% 60%))`;sw.style.background=g;code.textContent=g;}
document.getElementById('gen').onclick=gen;gen();

const c=document.getElementById('c'),x=c.getContext('2d'),hud=document.getElementById('hud');
let W,H,t,score=0;
function size(){W=c.width=c.clientWidth;H=c.height=c.clientHeight;}
function spawn(){t={x:30+Math.random()*(W-60),y:30+Math.random()*(H-60),r:20};}
function loop(){x.clearRect(0,0,W,H);const g=x.createRadialGradient(t.x,t.y,2,t.x,t.y,t.r);g.addColorStop(0,'#a855f7');g.addColorStop(1,'#22d3ee');x.fillStyle=g;x.beginPath();x.arc(t.x,t.y,t.r,0,7);x.fill();requestAnimationFrame(loop);}
c.onclick=e=>{const b=c.getBoundingClientRect();if(Math.hypot(e.clientX-b.left-t.x,e.clientY-b.top-t.y)<t.r+8){score++;hud.textContent='Score : '+score;spawn();}};
addEventListener('resize',()=>{size();spawn();});size();spawn();loop();

const c=document.getElementById('m'),x=c.getContext('2d');
let W,H,cols,y;
function init(){W=c.width=innerWidth;H=c.height=innerHeight;cols=Math.floor(W/14);y=Array(cols).fill(0);}
function draw(){x.fillStyle='rgba(7,10,15,.08)';x.fillRect(0,0,W,H);x.fillStyle='#22e39a';x.font='14px monospace';for(let i=0;i<cols;i++){const ch=String.fromCharCode(0x30a0+Math.random()*96);x.fillText(ch,i*14,y[i]*14);if(y[i]*14>H&&Math.random()>.975)y[i]=0;y[i]++;}}
init();addEventListener('resize',init);setInterval(draw,50);
